import 'dart:convert';
import 'package:http/http.dart' as http;
import 'package:shared_preferences/shared_preferences.dart';

class ApiClient {
  static const String baseUrl = 'https://api.example.com';
  static const String tokenKey = 'auth_token';
  static const String userKey = 'user_profile';

  static Future<String?> getAuthToken() async {
    final prefs = await SharedPreferences.getInstance();
    return prefs.getString(tokenKey);
  }

  static Future<void> setAuthToken(String token) async {
    final prefs = await SharedPreferences.getInstance();
    await prefs.setString(tokenKey, token);
  }

  static Future<void> clearAuth() async {
    final prefs = await SharedPreferences.getInstance();
    await prefs.remove(tokenKey);
    await prefs.remove(userKey);
  }

  static Future<http.Response> _makeRequest(
    String endpoint,
    String method, {
    Map<String, String>? headers,
    dynamic body,
  }) async {
    final token = await getAuthToken();
    final defaultHeaders = {
      'Content-Type': 'application/json',
      'Accept': 'application/json',
      if (token != null) 'Authorization': 'Bearer $token',
    };

    if (headers != null) {
      defaultHeaders.addAll(headers);
    }

    final url = Uri.parse('$baseUrl$endpoint');

    try {
      switch (method) {
        case 'GET':
          return await http.get(url, headers: defaultHeaders);
        case 'POST':
          return await http.post(
            url,
            headers: defaultHeaders,
            body: body is String ? body : jsonEncode(body),
          );
        case 'PUT':
          return await http.put(
            url,
            headers: defaultHeaders,
            body: body is String ? body : jsonEncode(body),
          );
        case 'DELETE':
          return await http.delete(url, headers: defaultHeaders);
        default:
          throw Exception('Unsupported HTTP method: $method');
      }
    } on Exception {
      rethrow;
    }
  }

  static Future<http.Response> get(String endpoint) {
    return _makeRequest(endpoint, 'GET');
  }

  static Future<http.Response> post(String endpoint, {dynamic body}) {
    return _makeRequest(endpoint, 'POST', body: body);
  }

  static Future<http.Response> put(String endpoint, {dynamic body}) {
    return _makeRequest(endpoint, 'PUT', body: body);
  }

  static Future<http.Response> delete(String endpoint) {
    return _makeRequest(endpoint, 'DELETE');
  }

  static Future<Map<String, dynamic>?> getUserProfile() async {
    final prefs = await SharedPreferences.getInstance();
    final userProfile = prefs.getString(userKey);
    if (userProfile != null) {
      return jsonDecode(userProfile);
    }
    return null;
  }

  static Future<void> saveUserProfile(Map<String, dynamic> profile) async {
    final prefs = await SharedPreferences.getInstance();
    await prefs.setString(userKey, jsonEncode(profile));
  }

  static Future<Map<String, dynamic>?> login(String email, String password) async {
    try {
      final response = await post('/auth/login', body: {
        'email': email,
        'password': password,
      });

      if (response.statusCode == 200) {
        final data = jsonDecode(response.body);
        final token = data['token'];
        final user = data['user'];

        if (token != null) {
          await setAuthToken(token);
        }

        if (user != null) {
          await saveUserProfile(user);
        }

        return data;
      } else {
        throw Exception('Login failed: ${response.statusCode}');
      }
    } on Exception {
      rethrow;
    }
  }

  static Future<void> logout() async {
    try {
      await delete('/auth/logout');
    } catch (e) {
      // Ignore logout errors
    }
    await clearAuth();
  }

  static Future<Map<String, dynamic>?> syncData() async {
    try {
      final response = await get('/sync');
      
      if (response.statusCode == 200) {
        final data = jsonDecode(response.body);
        return data;
      } else {
        throw Exception('Sync failed: ${response.statusCode}');
      }
    } on Exception {
      rethrow;
    }
  }
}